const PRICE_CACHE = new Map();
const YUAN_TO_WAN = 10000;
function csvEscape(val) {
  var s = String(val || '');
  if (s.includes(',') || s.includes('"') || s.includes('\n') || /^[=+\-@]/.test(s)) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}
function escHtml(str) {
  if (!str) return '';
  return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
}
function lookupMaterialPrice(spec) {
  if (!spec || spec.trim() === '') return null;
  const key = spec.trim().replace(/\s+/g, '');
  if (PRICE_CACHE.has(key)) return PRICE_CACHE.get(key);
  // Exact match (try both original and normalized)
  if (MATERIAL_PRICE_DB.has(key)) { PRICE_CACHE.set(key, MATERIAL_PRICE_DB.get(key)); return PRICE_CACHE.get(key); }
  if (MATERIAL_PRICE_DB.has(spec.trim())) { PRICE_CACHE.set(key, MATERIAL_PRICE_DB.get(spec.trim())); return PRICE_CACHE.get(spec.trim()); }
  // Fuzzy: try by \\-separated prefix matching (longest first)
  const parts = key.split('\\');
  for (let i = parts.length; i >= 1; i--) {
    const partial = parts.slice(0, i).join('\\');
    if (MATERIAL_PRICE_DB.has(partial)) {
      PRICE_CACHE.set(key, MATERIAL_PRICE_DB.get(partial));
      return PRICE_CACHE.get(key);
    }
  }
  // Try matching first part + any second part keywords
  if (parts.length >= 2) {
    for (const [dbKey, val] of MATERIAL_PRICE_DB) {
      const dbParts = dbKey.split('\\');
      if (dbParts[0] === parts[0]) {
        // Check if any keyword from the query matches the db entry
        for (let j = 1; j < parts.length; j++) {
          if (dbKey.includes(parts[j])) {
            PRICE_CACHE.set(key, val);
            return val;
          }
        }
      }
    }
  }
  // Try substring match: if the entire key appears inside a DB key
  for (const [dbKey, val] of MATERIAL_PRICE_DB) {
    if (dbKey.includes(key) || key.includes(dbKey.substring(0, Math.min(dbKey.length, 6)))) {
      PRICE_CACHE.set(key, val);
      return val;
    }
  }
  // Try matching by first character group (material type without specs)
  const firstWord = parts[0].replace(/[^a-zA-Z0-9一-鿿]/g, '');
  if (firstWord) {
    for (const [dbKey, val] of MATERIAL_PRICE_DB) {
      if (dbKey.startsWith(firstWord) || dbKey.includes(firstWord)) {
        PRICE_CACHE.set(key, val);
        return val;
      }
    }
  }
  PRICE_CACHE.set(key, null);
  return null;
}
